import{_ as t,B as o,o as i,c as e,a1 as l,D as n}from"./chunks/framework.Cv09mJXI.js";const p="/assets/security-platform-architecture.-VYUPaGa.png",s="/assets/android-stack.VohX5Qi8.png",c="/assets/technical-problems.B0GzbaM3.png",d="/assets/virtualapp-framework.DCFsr35E.png",u="/assets/virtualapp-process.DWWy9xIa.png",g="/assets/virtualapp-code.CNVBWM9H.png",M=JSON.parse('{"title":"基于沙盒技术的企业移动应用安全平台设计","description":"","frontmatter":{"sidebar":"auto","comment":"mobile-sandbox-technology"},"headers":[],"relativePath":"blog/mobile-sandbox-technology.md","filePath":"blog/mobile-sandbox-technology.md"}'),h={name:"blog/mobile-sandbox-technology.md"};function m(A,r,b,P,_,V){const a=o("site-footer");return i(),e("div",null,[r[0]||(r[0]=l('<h1 id="基于沙盒技术的企业移动应用安全平台设计" tabindex="-1">基于沙盒技术的企业移动应用安全平台设计 <a class="header-anchor" href="#基于沙盒技术的企业移动应用安全平台设计" aria-label="Permalink to &quot;基于沙盒技术的企业移动应用安全平台设计&quot;">​</a></h1><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>移动互联网的飞速发展, 改变了企业传统的业务模式, 提高了工作效率. 但同时也给企业的数据安全带来了巨大的挑战, 我们面对各种攻击的可能性会大 大增加, 面临潜在的风险:</p><ul><li>移动设备中的不安全应用程序会危及到企业网络的安全；</li><li>移动设备可能在不安全的网络(如公共 WiFi 热 点)中使用, 容易造成恶意软件感染和数据泄漏；</li><li>越狱或获取 Root 权限移动设备会带更多风险；</li><li>移动设备被盗, 在未经授权的情况下访问公司的网络或者泄漏敏感数据。</li></ul><p>企业移动应用安全平台由四部分功能组成, 安装在手机上的 <strong>安全容器</strong>、<strong>安全加固 SDK</strong>, <strong>Web 管理门户</strong> 和 <strong>通信代理</strong>, 各部分的功能及其相互间的关系如下所示:</p><p><img src="'+p+'" alt=""></p><h2 id="android-安全架构" tabindex="-1">Android 安全架构 <a class="header-anchor" href="#android-安全架构" aria-label="Permalink to &quot;Android 安全架构&quot;">​</a></h2><p>Android 系统采用分层的体系结构，分别为: Applications(核心应用程序)、Application Framework(开发框架包)、Libraries(系统运行库或者是 c/c++ 核心库)、Hardware Abstraction Layer(硬件抽象层)、Linux Kernel(Linux 内核)。</p><p><img src="'+s+'" alt=""></p><p>Android 系统采用分层的系统架构进行设计，每层都有其严格的安全规范和强健的安全架构。Android 的主要安全机制在内核层和系统框架层。在系统框架层，Android 则采用了权限机制、签名机制和沙箱机制，来保护系统的安全，隔离不同进程之间的资源访问，授权访问系统资源和服务，禁止非授权访问的发生。</p><p>权限机制是 Android 系统框架层提供的，是对应用访问公共资源和服务进行强制访问的安全策略。应用如果要使用公共资源和服务，必须要在配置文件中声明需要使用对应资源的权限，否则将无法得到授权，致使不能使用其资源，但是权限机制采用的全部肯定和全部否定的方式，把最终的确定权交给了用户，用户在不具备相关的安全知识的情况下是很难做出合适的判断的。</p><p>签名机制是应用中包含一个采用非对称加密方式存储的数字证书，由于私钥在开发人员手中，所以数字证书能够保证开发人员对其应用的合法拥有权。虽然 Android 系统提供了签名机制来保护开发人员的合法拥有权，但是并没有提供验证应用是否被恶意的二次重打包，这使得应用被注入一些恶意的代码，来获取非法的收益或达成恶意的目的。</p><p>沙箱虽然提供了进程隔离的机制，保证运行时应用的进程空间不会被恶意的修改，但是沙箱并没有在运行时验证是否运行环境是否安全，是否系统的关键函数的地址发生了改变，一旦系统的在进入沙箱前就已经被恶意修改，沙箱中的应用也将受到恶意的威胁。</p><p>目前基于容器的 Android 加固方案和沙箱技术免安装应用的管理，本质上都是基于 Android 系统插件化的技术，APK 沙箱需要解决以下几个问题：</p><p><img src="'+c+'" alt=""></p><h2 id="virtualapp-沙箱原理" tabindex="-1">VirtualApp 沙箱原理 <a class="header-anchor" href="#virtualapp-沙箱原理" aria-label="Permalink to &quot;VirtualApp 沙箱原理&quot;">​</a></h2><p>VirtualApp 是一个开源的 Android App 虚拟化引擎，允许在其中创建虚拟空间，并在这个虚拟空间中运行其他应用。Android 应用隔离是基于 Linux 系统的多用户机制实现的，即每个应用在安装时被分配了不同的 Linux 用户 uid/gid。而在 VirtualApp 中，client 应用（通过 VirtualApp 安装的应用）与 host 应用（即 VirtualApp 本身）是具有相同用户 uid 的。</p><p>因此，VirtualApp 在运行时，包含以下三部分：</p><p><img src="'+d+'" alt=""></p><ul><li>Main Process，进程名 io.virtualapp，主要负责 VirtualApp 用户界面及应用管理</li><li>VA Server Process，进程名 io.virtualapp:x，主要负责系统服务的代理，是通过 Content Provider 启动的</li><li>Client App Process，进程名 io.virtualapp:p[0-…]，作为将来运行 client 应用的进程，当 client 应用启动后，其进程名会更新为 client 应用的包名</li></ul><p>下面是在 VirtualApp 中运行应用后通过 ps 命令得到的结果：</p><p><img src="'+u+'" alt=""></p><p>各列参数意义：</p><ul><li>USER: 进程当前用户；</li><li>PID: Process ID，进程 ID；</li><li>PPID: Process Parent ID，进程的父进程 ID；</li><li>VSIZE: Virtual Size，进程的虚拟内存大小；</li><li>RSS: Resident Set Size，实际驻留&quot;在内存中&quot;的内存大小；</li><li>WCHAN: 休眠进程在内核中的地址；</li><li>PC: Program Counter；</li><li>NAME: 进程名.</li></ul><p>可以看到，以上进程，均是以 VirtualApp 的用户 uid 运行的。因此，Android 应用隔离此时不再适用，我们可以对 client 应用进行 hook 而无需 root 权限。</p><h2 id="virtualapp-源码结构" tabindex="-1">VirtualApp 源码结构 <a class="header-anchor" href="#virtualapp-源码结构" aria-label="Permalink to &quot;VirtualApp 源码结构&quot;">​</a></h2><p><img src="'+g+'" alt=""></p><p><strong>1. java/android: 覆盖了系统的隐藏类</strong></p><p><strong>content/pm/PackageParser</strong>: 主要对应 android.content.pm.PackageParser，主要作用是解析 APK;</p><p><strong>location/LocationRequest</strong>: 对应于 android.location.LocationRequest，该类是一个可持久化的 Parcelable，主要作用是设置 LocationManagerService 的参数。</p><p><strong>2. com.lody.virtual: 框架的主体代码</strong></p><p><strong>client</strong>: 运行在客户端的代码，指加载到 VA 中的子程序在被 VA 代理(hook)之后,所运行的代码;</p><p><strong>server</strong>: server 端代码，VA 伪造了一套 framework 层系统 service 的代码，他在一个独立的服务中记录管理组件的各种 Recorder，其逻辑其实与系统原生的相近，通过 Binder 与 client 端的 ipc 包中的 VXXXXManager 通讯。诸如 AMS(VAMS),PMS(VPMS);</p><p><strong>remote</strong>: 一些可序列化 Model，继承于 Parcelable;</p><p><strong>os</strong>: 处理系统环境，如多用户;</p><p><strong>helper</strong>: 框架工具类。</p><p><strong>3. mirror：系统 framework 的镜像</strong></p><p>实现了与 framework 层相对应的结构，封装了反射获取系统隐藏字段和方法的，便于直接调用获取或者赋值以及调用方法。</p><h2 id="mam-发展的现状" tabindex="-1">MAM 发展的现状 <a class="header-anchor" href="#mam-发展的现状" aria-label="Permalink to &quot;MAM 发展的现状&quot;">​</a></h2><p>移动应用程序管理（MAM）背后的想法是我们将安全策略应用于单个应用程序而不是整个设备。这意味着各种应用程序可以应用独特的策略，并且无论设备的管理状态如何，它们都将受到保护和管理。基本的应用程序管理功能通常包括身份验证，VPN，加密和远程擦除。应用程序还连接到可以控制身份验证，发出远程擦除命令或使用 IT 创建的策略控制应用程序的服务器。</p><p>前言部分我们我们知道沙箱技术主要用于企业应用管理的安全容器(安全桌面)，MAM 中最关键的技术就是 APP Wrapping 和 Secure Container 部分，它把一个移动设备划分出两个工作区，从而实现个人空间与企业工作空间的隔离。这些关键技术通俗理解就是 iOS、Android，WinPhone 上的应用虚拟化，它没有一个标准接口可遵循，完全靠各 MAM 厂商自己的技术功力来实现。</p><ul><li>APP Wrapping (封装或者打包) —— 透过对应用封装打包或通过集成 SDK 方法，控制服务和安全管理，对于应用的分发，访问和策略管理至关重要。</li><li>Secure container (容器或沙盒) —— 应用级别的竖井，加密存储和传输状态的数据，对消息和应用数据提供隔离保护，设备其他部分无法访问。</li></ul><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="https://myslide.cn/slides/1022" target="_blank" rel="noreferrer">APK 沙箱技术在平台型 App 中 的架构实战</a></li><li><a href="http://rk700.github.io/2017/03/15/virtualapp-basic/" target="_blank" rel="noreferrer">VirtualApp 沙盒基本原理</a></li><li><a href="https://blog.csdn.net/ganyao939543405/article/details/76146760" target="_blank" rel="noreferrer">Android 双开沙箱 VirtualApp 源码分析</a></li><li><a href="http://blog.51cto.com/virtualworld/1557553" target="_blank" rel="noreferrer">各大 EMM 厂商功能比较 第二部分 MAM &amp; Container 比较</a></li></ul>',44)),n(a)])}const k=t(h,[["render",m]]);export{M as __pageData,k as default};
